// ============================================================
// Gita Quiz DB Checker - Validate ALL Records + Aggregate
// Mode: Run Once for All Items (no SplitInBatches needed)
// IGM 2025 | NIC Kurukshetra
// ============================================================

const VALID_DISTRICTS = [
  'kurukshetra', 'kkr', 'ambala', 'karnal', 'panipat',
  'yamunanagar', 'kaithal', 'pehowa', 'thanesar',
  'rohtak', 'hisar', 'faridabad', 'gurugram', 'jind',
  'bhiwani', 'sirsa', 'sonipat', 'rewari', 'mahendragarh'
];

const DISTRICT_NORMALIZE = {
  'kkr': 'Kurukshetra', 'kurukshetra': 'Kurukshetra',
  'thanesar': 'Kurukshetra', 'pehowa': 'Kurukshetra',
  'ambala': 'Ambala', 'karnal': 'Karnal',
  'panipat': 'Panipat', 'yamunanagar': 'Yamunanagar',
  'kaithal': 'Kaithal', 'rohtak': 'Rohtak',
  'hisar': 'Hisar', 'faridabad': 'Faridabad',
  'gurugram': 'Gurugram', 'jind': 'Jind',
  'bhiwani': 'Bhiwani', 'sirsa': 'Sirsa',
  'sonipat': 'Sonipat', 'rewari': 'Rewari',
  'mahendragarh': 'Mahendragarh'
};

const allItems = $input.all();
const cleanRows = [];
const errorRows = [];
const fingerprintsSeen = {};
const duplicates = [];
const issueMap = {};

for (const it of allItems) {
  const item = it.json;
  const issues = [];

  // 1. Validate name
  const rawName = (item.participant_name || '').toString().trim();
  if (!rawName) {
    issues.push('MISSING_NAME');
  } else if (rawName.split(' ').filter(Boolean).length < 2) {
    issues.push('INCOMPLETE_NAME');
  }
  const cleanName = rawName.toLowerCase().replace(/\b\w/g, c => c.toUpperCase());

  // 2. Validate mobile
  const rawMobile = (item.mobile_number || '').toString().trim();
  const digitsOnly = rawMobile.replace(/[^0-9]/g, '');
  if (!rawMobile) {
    issues.push('MISSING_MOBILE');
  } else if (/[a-zA-Z]/.test(rawMobile)) {
    issues.push('INVALID_CHARS_IN_MOBILE');
  } else if (digitsOnly.length !== 10) {
    issues.push('MOBILE_NOT_10_DIGITS');
  } else if (!/^[6-9]/.test(digitsOnly)) {
    issues.push('MOBILE_INVALID_PREFIX');
  }
  const cleanMobile = digitsOnly;

  // 3. Validate district
  const rawDistrict = (item.district || '').toString().trim();
  const districtKey = rawDistrict.toLowerCase();
  if (!rawDistrict) {
    issues.push('MISSING_DISTRICT');
  } else if (!VALID_DISTRICTS.includes(districtKey)) {
    issues.push('UNKNOWN_DISTRICT');
  }
  const cleanDistrict = DISTRICT_NORMALIZE[districtKey] || rawDistrict;

  // 4. Fingerprint for duplicates
  const fingerprint = `${cleanName.toLowerCase().replace(/\s/g,'')}|${cleanMobile}`;
  if (fingerprintsSeen[fingerprint]) {
    issues.push('DUPLICATE_RECORD');
    duplicates.push(rawName || 'Unknown');
  } else {
    fingerprintsSeen[fingerprint] = true;
  }

  // 5. Track issue types
  issues.forEach(i => { issueMap[i] = (issueMap[i] || 0) + 1; });

  const status = issues.length === 0 ? 'CLEAN' : 'INVALID';
  const checkedAt = new Date().toISOString();

  const record = {
    original_name: rawName,
    original_mobile: rawMobile,
    original_district: rawDistrict,
    clean_name: cleanName,
    clean_mobile: cleanMobile,
    clean_district: cleanDistrict,
    status,
    issues: issues.join(', ') || 'None',
    issue_count: issues.length,
    fingerprint,
    checked_at: checkedAt
  };

  if (status === 'CLEAN') cleanRows.push(record);
  else errorRows.push(record);
}

// Build summary
const totalRecords = allItems.length;
const cleanCount = cleanRows.length;
const invalidCount = errorRows.length;
const qualityPercent = totalRecords > 0 ? Math.round((cleanCount / totalRecords) * 100) : 0;
const issuesSummary = Object.entries(issueMap).map(([k,v]) => `${k}: ${v}`).join(', ') || 'No issues';
const checkedAt = new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' });

// Return one output item with everything
return [
  {
    clean_rows: cleanRows,
    error_rows: errorRows,
    total_records: totalRecords,
    clean_count: cleanCount,
    invalid_count: invalidCount,
    duplicate_count: duplicates.length,
    duplicates_names: duplicates.join(', ') || 'None',
    issues_breakdown: issuesSummary,
    quality_percent: qualityPercent,
    checked_at: checkedAt
  }
];

// Write CLEAN rows to Clean_DB sheet
// Returns one item per clean record for Google Sheets append
const data = $input.first().json;
return data.clean_rows.map(row => ({
  Name: row.clean_name,
  Mobile: row.clean_mobile,
  District: row.clean_district,
  Fingerprint: row.fingerprint,
  Checked_At: row.checked_at
}));

// Write INVALID rows to Error_Report sheet
const data = $input.first().json;
return data.error_rows.map(row => ({
  Original_Name: row.original_name,
  Original_Mobile: row.original_mobile,
  Original_District: row.original_district,
  Status: row.status,
  Issues: row.issues,
  Issue_Count: row.issue_count,
  Checked_At: row.checked_at
}));

// Format Twilio WhatsApp message
// Extract AI text from Groq HTTP Response
const stats = $('Validate All Records').first().json;
const raw = $input.item.json;

// Groq HTTP response shape: { choices: [ { message: { content: '...' } } ] }
let aiReport = 'AI summary unavailable';
try {
  if (raw.choices && raw.choices[0] && raw.choices[0].message) {
    aiReport = raw.choices[0].message.content;
  } else if (raw.text) {
    aiReport = raw.text;
  }
} catch(e) {
  aiReport = 'Could not parse AI response';
}

const emoji = stats.quality_percent >= 90 ? '✅' : stats.quality_percent >= 70 ? '⚠️' : '🔴';

const message = `${emoji} *Gita Quiz DB Check Report*
📅 ${stats.checked_at} IST

📊 *Stats:*
• Total: ${stats.total_records} records
• Clean: ${stats.clean_count} (${stats.quality_percent}%)
• Invalid: ${stats.invalid_count}
• Duplicates: ${stats.duplicate_count}

🤖 *AI Analysis:*
${aiReport}

_Powered by NIC Kurukshetra | IGM 2025_`;

return { message };

